import { getServerSession } from "next-auth";
import { authOptions } from "@/lib/auth";
import { prisma } from "@/lib/prisma";
import { redirect } from "next/navigation";
import Link from "next/link";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Bookmark, FileText, Database } from "lucide-react";

export const dynamic = "force-dynamic";

export default async function BookmarksPage({ searchParams }: { searchParams: { tab?: string } }) {
  const session = await getServerSession(authOptions);
  if (!session?.user?.id) redirect("/login");

  const activeTab = searchParams.tab || "notes";

  const bookmarks = await prisma.bookmark.findMany({
    where: { userId: session.user.id },
    include: {
      note: { include: { author: { select: { fullName: true } } } },
      resource: { include: { author: { select: { fullName: true } } } }
    },
    orderBy: { createdAt: "desc" }
  });

  const noteBookmarks = bookmarks.filter(b => b.itemType === "NOTE" && b.note);
  const resourceBookmarks = bookmarks.filter(b => b.itemType === "RESOURCE" && b.resource);

  return (
    <div className="container mx-auto px-4 py-8 max-w-5xl space-y-8">
      <div>
        <h1 className="text-3xl font-bold tracking-tight">Bookmarks</h1>
        <p className="text-muted-foreground mt-1 text-lg">Your saved notes and resources.</p>
      </div>

      <div className="flex border-b">
        <Link href="/bookmarks?tab=notes" className={`pb-3 px-4 font-medium transition-colors border-b-2 ${activeTab === 'notes' ? 'border-primary text-primary' : 'border-transparent text-muted-foreground hover:text-foreground'}`}>
          Notes ({noteBookmarks.length})
        </Link>
        <Link href="/bookmarks?tab=resources" className={`pb-3 px-4 font-medium transition-colors border-b-2 ${activeTab === 'resources' ? 'border-primary text-primary' : 'border-transparent text-muted-foreground hover:text-foreground'}`}>
          Resources ({resourceBookmarks.length})
        </Link>
      </div>

      {activeTab === "notes" && (
        <div className="space-y-6">
          {noteBookmarks.length > 0 ? (
            <div className="grid sm:grid-cols-2 gap-4">
              {noteBookmarks.map(({ note }) => note && (
                <Card key={note.id} className="hover:border-primary/50 transition-colors">
                  <CardHeader className="p-4 pb-2">
                    <div className="flex justify-between items-start">
                      <span className="text-[10px] uppercase font-bold tracking-wider text-muted-foreground bg-muted px-2 py-0.5 rounded">
                        {note.tags.split(',')[0]}
                      </span>
                    </div>
                    <CardTitle className="text-lg mt-2 line-clamp-2 leading-tight">{note.title}</CardTitle>
                  </CardHeader>
                  <CardContent className="p-4 pt-2">
                    <p className="text-sm text-muted-foreground mb-4">By {note.author?.fullName || "Member"}</p>
                    <Link href={`/notes/${note.id}`}>
                      <Button variant="secondary" className="w-full h-8">Read Note</Button>
                    </Link>
                  </CardContent>
                </Card>
              ))}
            </div>
          ) : (
             <div className="text-center py-16 border border-dashed rounded-lg bg-muted/10">
               <Bookmark className="h-12 w-12 text-muted-foreground mb-4 opacity-50 mx-auto" />
               <h3 className="text-lg font-medium mb-2">No notes saved</h3>
               <p className="text-muted-foreground max-w-sm mx-auto mb-6">
                 When you find a helpful community note, click the bookmark icon to save it here.
               </p>
               <Link href="/notes"><Button variant="outline">Browse Notes</Button></Link>
             </div>
          )}
        </div>
      )}

      {activeTab === "resources" && (
        <div className="space-y-6">
          {resourceBookmarks.length > 0 ? (
             <div className="grid sm:grid-cols-2 gap-4">
              {resourceBookmarks.map(({ resource }) => resource && (
                <Card key={resource.id} className="hover:border-primary/50 transition-colors">
                  <CardHeader className="p-4 pb-2">
                    <div className="flex justify-between items-start">
                      <span className="text-[10px] uppercase font-bold tracking-wider text-primary bg-primary/10 px-2 py-0.5 rounded">
                        {resource.type}
                      </span>
                    </div>
                    <CardTitle className="text-lg mt-2 line-clamp-2 leading-tight">{resource.title}</CardTitle>
                    <CardDescription className="line-clamp-2 text-sm mt-1">{resource.description}</CardDescription>
                  </CardHeader>
                  <CardContent className="p-4 pt-2 mt-auto">
                    <Link href={`/resources/${resource.id}`}>
                      <Button variant="secondary" className="w-full h-8 mt-2">View Resource</Button>
                    </Link>
                  </CardContent>
                </Card>
              ))}
            </div>
          ) : (
            <div className="text-center py-16 border border-dashed rounded-lg bg-muted/10">
               <Bookmark className="h-12 w-12 text-muted-foreground mb-4 opacity-50 mx-auto" />
               <h3 className="text-lg font-medium mb-2">No resources saved</h3>
               <p className="text-muted-foreground max-w-sm mx-auto mb-6">
                 When you find a useful PDF, link, or video, click the bookmark icon to save it here.
               </p>
               <Link href="/resources"><Button variant="outline">Browse Resources</Button></Link>
             </div>
          )}
        </div>
      )}
    </div>
  );
}

import { redirect } from "next/navigation";
import { getServerSession } from "next-auth";
import { authOptions } from "@/lib/auth";
import { prisma } from "@/lib/prisma";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Terminal, Lightbulb, Map, Bookmark, Lock, Bell, Calendar, FileText, Database } from "lucide-react";
import Link from "next/link";

export default async function DashboardPage() {
  const session = await getServerSession(authOptions);

  if (!session) {
    redirect("/login");
  }

  // Fetch pinned announcements
  const announcements = await prisma.announcement.findMany({
    where: { isPinned: true },
    orderBy: { createdAt: "desc" }
  });

  // Fetch latest notes
  const latestNotes = await prisma.note.findMany({
    where: { status: "PUBLISHED" },
    orderBy: { createdAt: "desc" },
    take: 3,
    include: { author: { select: { fullName: true } } }
  });

  // Fetch latest resources
  const latestResources = await prisma.resource.findMany({
    where: { status: "PUBLISHED" },
    orderBy: { createdAt: "desc" },
    take: 3,
  });

  // Fetch upcoming events
  const upcomingEvents = await prisma.event.findMany({
    where: { startTime: { gte: new Date() } },
    orderBy: { startTime: "asc" },
    take: 3,
  });

  return (
    <div className="container mx-auto px-4 py-8 max-w-6xl space-y-8">
      {/* Pinned Announcements */}
      {announcements.length > 0 && (
        <div className="space-y-4">
          {announcements.map(announcement => (
            <div key={announcement.id} className="bg-primary/15 border border-primary/30 text-primary-foreground p-4 rounded-lg flex items-start gap-4 shadow-sm">
              <Bell className="h-5 w-5 mt-0.5 text-primary flex-shrink-0" />
              <div>
                <h4 className="font-semibold text-primary mb-1">Pinned Announcement</h4>
                <p className="text-sm text-foreground/90">{announcement.content}</p>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Welcome Header */}
      <div>
        <h1 className="text-3xl font-bold tracking-tight">Welcome back, {session.user.name || session.user.email?.split("@")[0]}</h1>
        <p className="text-muted-foreground mt-1">Here is what's happening in the DevOps Hub community.</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-4 gap-8">
        {/* Main Feed (3 Cols on Desktop) */}
        <div className="md:col-span-3 space-y-8">

          {/* Latest Notes */}
          <section className="space-y-4">
            <div className="flex items-center justify-between">
              <h2 className="text-xl font-bold flex items-center gap-2"><FileText className="h-5 w-5 text-primary" /> Latest Community Notes</h2>
              <Link href="/notes"><Button variant="ghost" size="sm">View all</Button></Link>
            </div>
            {latestNotes.length > 0 ? (
              <div className="grid sm:grid-cols-2 gap-4">
                {latestNotes.map(note => (
                  <Card key={note.id} className="hover:border-primary/50 transition-colors">
                    <CardHeader className="p-4 pb-2">
                      <div className="flex justify-between items-start">
                        <span className="text-xs bg-muted px-2 py-1 rounded text-muted-foreground">{note.tags.split(',')[0]}</span>
                        <span className="text-xs text-muted-foreground">{note.readTime} min read</span>
                      </div>
                      <CardTitle className="text-lg mt-2 line-clamp-2 leading-tight">{note.title}</CardTitle>
                    </CardHeader>
                    <CardContent className="p-4 pt-0">
                      <p className="text-sm text-muted-foreground mb-4">By {note.author.fullName || "Community Member"}</p>
                      <Link href={`/notes/${note.id}`}>
                        <Button variant="secondary" className="w-full h-8 cursor-pointer">Read Note</Button>
                      </Link>
                    </CardContent>
                  </Card>
                ))}
              </div>
            ) : (
              <div className="text-center py-8 border border-dashed rounded-lg bg-muted/10">
                <p className="text-muted-foreground mb-4">No notes published yet.</p>
                <Link href="/notes/new"><Button variant="outline">Write the first note</Button></Link>
              </div>
            )}
          </section>

          {/* Latest Resources */}
          <section className="space-y-4">
            <div className="flex items-center justify-between">
              <h2 className="text-xl font-bold flex items-center gap-2"><Database className="h-5 w-5 text-primary" /> Curated Resources</h2>
              <Link href="/resources"><Button variant="ghost" size="sm">View all</Button></Link>
            </div>
            {latestResources.length > 0 ? (
               <div className="grid sm:grid-cols-2 gap-4">
                {latestResources.map(resource => (
                  <Card key={resource.id}>
                    <CardHeader className="p-4 pb-2">
                      <div className="flex justify-between items-start">
                        <span className="text-xs font-medium uppercase text-primary tracking-wider">{resource.type}</span>
                      </div>
                      <CardTitle className="text-lg mt-1 line-clamp-1">{resource.title}</CardTitle>
                      <CardDescription className="line-clamp-2 text-xs mt-1">{resource.description}</CardDescription>
                    </CardHeader>
                    <CardContent className="p-4 pt-2">
                       <Link href={`/resources/${resource.id}`}>
                        <Button variant="outline" className="w-full h-8">View Resource</Button>
                      </Link>
                    </CardContent>
                  </Card>
                ))}
               </div>
            ) : (
              <div className="text-center py-8 border border-dashed rounded-lg bg-muted/10">
                <p className="text-muted-foreground mb-4">No resources shared yet.</p>
                <Link href="/resources/new"><Button variant="outline">Share a resource</Button></Link>
              </div>
            )}
          </section>

        </div>

        {/* Sidebar (1 Col on Desktop) */}
        <div className="space-y-6">
          {/* Quick Links */}
          <Card>
            <CardHeader className="pb-3">
              <CardTitle className="text-sm font-semibold uppercase tracking-wider text-muted-foreground">Quick Links</CardTitle>
            </CardHeader>
            <CardContent className="space-y-2">
              <Link href="/bookmarks" className="flex items-center gap-3 p-2 rounded hover:bg-muted transition-colors">
                <Bookmark className="h-4 w-4 text-primary" />
                <span className="text-sm font-medium">My Bookmarks</span>
              </Link>
              <Link href="/roadmap" className="flex items-center gap-3 p-2 rounded hover:bg-muted transition-colors">
                <Map className="h-4 w-4 text-primary" />
                <span className="text-sm font-medium">Learning Roadmap</span>
              </Link>
            </CardContent>
          </Card>

          {/* Upcoming Events */}
          <Card>
            <CardHeader className="pb-3">
              <CardTitle className="text-sm font-semibold uppercase tracking-wider text-muted-foreground">Upcoming Events</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              {upcomingEvents.length > 0 ? (
                upcomingEvents.map(event => (
                  <div key={event.id} className="space-y-1">
                    <p className="font-medium text-sm leading-tight">{event.title}</p>
                    <div className="flex items-center text-xs text-muted-foreground gap-1">
                      <Calendar className="h-3 w-3" />
                      {new Date(event.startTime).toLocaleDateString()}
                    </div>
                  </div>
                ))
              ) : (
                <p className="text-sm text-muted-foreground text-center py-2">No upcoming events.</p>
              )}
              {upcomingEvents.length > 0 && (
                <Link href="/events"><Button variant="link" className="px-0 h-auto text-xs w-full justify-start mt-2">See all events ΓåÆ</Button></Link>
              )}
            </CardContent>
          </Card>

          {/* Coming Soon Locked */}
          <div className="space-y-4 pt-4 border-t">
            <h3 className="text-sm font-semibold uppercase tracking-wider text-muted-foreground">Coming Soon</h3>

            <div className="border border-dashed rounded p-3 bg-muted/20 opacity-80 flex items-start gap-3">
              <Lock className="h-4 w-4 text-muted-foreground mt-0.5" />
              <div>
                <p className="text-xs font-semibold">Community Chat</p>
                <p className="text-[10px] text-muted-foreground mt-0.5 leading-tight">Discord-style real-time chat exclusively for DevOps.</p>
              </div>
            </div>

            <div className="border border-dashed rounded p-3 bg-muted/20 opacity-80 flex items-start gap-3">
              <Lock className="h-4 w-4 text-muted-foreground mt-0.5" />
              <div>
                <p className="text-xs font-semibold">Job Board</p>
                <p className="text-[10px] text-muted-foreground mt-0.5 leading-tight">Curated roles, no spam. Real engineer opportunities.</p>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

import { notFound } from "next/navigation";
import { getServerSession } from "next-auth";
import { authOptions } from "@/lib/auth";
import { prisma } from "@/lib/prisma";
import { NoteActions } from "@/components/note-actions";
import { Clock, Eye, Calendar, User as UserIcon } from "lucide-react";

export const dynamic = "force-dynamic";

export default async function NoteDetailPage({ params }: { params: { id: string } }) {
  const session = await getServerSession(authOptions);

  const note = await prisma.note.findUnique({
    where: { id: params.id },
    include: {
      author: { select: { fullName: true } },
      _count: { select: { upvotes: true } }
    }
  });

  if (!note || (note.status !== "PUBLISHED" && session?.user?.role !== "ADMIN" && note.authorId !== session?.user?.id)) {
    notFound();
  }

  // Increment views
  await prisma.note.update({
    where: { id: note.id },
    data: { views: { increment: 1 } }
  });

  // Check state
  let hasUpvoted = false;
  let hasBookmarked = false;

  if (session?.user?.id) {
    const [upvote, bookmark] = await Promise.all([
      prisma.upvote.findFirst({ where: { userId: session.user.id, itemType: "NOTE", noteId: note.id } }),
      prisma.bookmark.findFirst({ where: { userId: session.user.id, itemType: "NOTE", noteId: note.id } })
    ]);
    hasUpvoted = !!upvote;
    hasBookmarked = !!bookmark;
  }

  return (
    <article className="container mx-auto px-4 py-8 max-w-4xl">
      {note.coverImage && (
        <div className="w-full h-48 md:h-80 bg-muted rounded-xl overflow-hidden mb-8 border">
          <img src={note.coverImage} alt={note.title} className="w-full h-full object-cover" onError={(e) => (e.currentTarget.style.display = 'none')} />
        </div>
      )}

      <header className="mb-8 space-y-4">
        <div className="flex flex-wrap gap-2">
          {note.tags.split(',').map(t => (
            <span key={t} className="text-xs uppercase tracking-wider bg-secondary text-secondary-foreground font-semibold px-2 py-1 rounded">
              {t.trim()}
