              <div className="bg-primary/20 p-1 rounded-full"><UserIcon className="h-4 w-4 text-primary" /></div>
              {note.author.fullName || "Community Member"}
            </div>
            <div className="flex items-center gap-1">
              <Calendar className="h-4 w-4" />
              {new Date(note.createdAt).toLocaleDateString()}
            </div>
            <div className="flex items-center gap-1">
              <Clock className="h-4 w-4" />
              {note.readTime} min read
            </div>
            <div className="flex items-center gap-1">
              <Eye className="h-4 w-4" />
              {note.views + 1} views
            </div>
          </div>

          <NoteActions 
            itemId={note.id} 
            itemType="NOTE" 
            initialUpvoteCount={note._count.upvotes} 
            hasUpvoted={hasUpvoted} 
            hasBookmarked={hasBookmarked} 
          />
        </div>
      </header>

      {/* Note Content body formatting */}
      <div 
        className="prose prose-sm md:prose-base dark:prose-invert max-w-none 
        prose-headings:tracking-tight prose-a:text-primary 
        prose-code:bg-muted prose-code:px-1 prose-code:py-0.5 prose-code:rounded prose-code:before:content-none prose-code:after:content-none
        prose-pre:bg-muted prose-pre:text-muted-foreground prose-pre:border"
        dangerouslySetInnerHTML={{ __html: note.content }}
      />

    </article>
  );
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardContent } from "@/components/ui/card";
import { Editor } from "@/components/editor";
import { Save, Code2, Type } from "lucide-react";

export default function NewNotePage() {
  const router = useRouter();
  const [mode, setMode] = useState<"VISUAL" | "JSON">("VISUAL");
  const [title, setTitle] = useState("");
  const [coverImage, setCoverImage] = useState("");
  const [tags, setTags] = useState("");
  const [content, setContent] = useState("<p>Write your amazing DevOps note here...</p>");
  const [jsonInput, setJsonInput] = useState("");

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const handleJsonPaste = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    const val = e.target.value;
    setJsonInput(val);
    try {
      const parsed = JSON.parse(val);
      if (parsed.title) setTitle(parsed.title);
      if (parsed.coverImage) setCoverImage(parsed.coverImage);
      if (parsed.tags) setTags(parsed.tags);
      if (parsed.content) setContent(parsed.content);
      setError("");
    } catch (e) {
      setError("Invalid JSON format");
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError("");

    try {
      const res = await fetch("/api/notes", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ title, coverImage, tags, content }),
      });

      const data = await res.json();
      if (!res.ok) throw new Error(data.message || "Failed to submit note");

      router.push("/notes");
      router.refresh();
    } catch (err: any) {
      setError(err.message);
      setLoading(false);
    }
  };

  return (
    <div className="container mx-auto px-4 py-8 max-w-4xl space-y-8">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Write a Note</h1>
          <p className="text-muted-foreground mt-1 text-sm">Share your DevOps knowledge with the community</p>
        </div>
        <div className="flex bg-muted p-1 rounded-lg">
          <Button 
            variant={mode === "VISUAL" ? "secondary" : "ghost"} 
            size="sm"
            onClick={() => setMode("VISUAL")}
          ><Type className="h-4 w-4 mr-2" /> Visual</Button>
          <Button 
            variant={mode === "JSON" ? "secondary" : "ghost"} 
            size="sm"
            onClick={() => setMode("JSON")}
          ><Code2 className="h-4 w-4 mr-2" /> JSON Mode</Button>
        </div>
      </div>

      <Card>
        <CardContent className="pt-6">
          <form onSubmit={handleSubmit} className="space-y-6">
            {error && (
              <div className="p-3 bg-destructive/15 text-destructive border border-destructive/20 rounded-md text-sm">
                {error}
              </div>
            )}

            {mode === "JSON" && (
              <div className="space-y-2">
                <label className="text-sm font-medium leading-none">Paste JSON object</label>
                <p className="text-xs text-muted-foreground">Requires keys: title, coverImage, tags, content (HTML string)</p>
                <textarea 
                  value={jsonInput}
                  onChange={handleJsonPaste}
                  className="w-full h-48 rounded-md border border-input bg-background px-3 py-2 text-sm font-mono ring-offset-background focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
                  placeholder={'{\n  "title": "My Note",\n  "content": "<p>Hello</p>",\n  "tags": "docker, aws"\n}'}
                />
              </div>
            )}

            <div className={`space-y-6 ${mode === "JSON" ? "opacity-50 pointer-events-none" : ""}`}>
              <div className="space-y-2">
                <label className="text-sm font-medium leading-none">Title</label>
                <Input 
                  value={title} 
                  onChange={e => setTitle(e.target.value)} 
                  placeholder="e.g. A Deep Dive into Kubernetes Pods" 
                  required 
                />
              </div>

              <div className="space-y-2">
                <label className="text-sm font-medium leading-none">Cover Image URL (Optional)</label>
                <Input 
                  value={coverImage} 
                  onChange={e => setCoverImage(e.target.value)} 
                  placeholder="https://example.com/image.png" 
                />
                {coverImage && (
                  <div className="mt-2 text-xs text-muted-foreground">Preview:
                    <img src={coverImage} alt="Cover preview" className="mt-1 h-32 w-auto border rounded object-cover bg-muted" onError={(e) => (e.currentTarget.style.display = 'none')} />
                  </div>
                )}
              </div>

              <div className="space-y-2">
                <label className="text-sm font-medium leading-none">Tags (comma separated)</label>
                <Input 
                  value={tags} 
                  onChange={e => setTags(e.target.value)} 
                  placeholder="docker, kubernetes, cicd" 
                  required 
                />
              </div>

              <div className="space-y-2">
                <label className="text-sm font-medium leading-none mb-2 block">Content</label>
                {/* Visual Editor Component */}
                <Editor content={content} onChange={setContent} />
              </div>
            </div>

            <div className="flex justify-end pt-4 border-t">
              <Button type="submit" disabled={loading} size="lg">
                <Save className="h-4 w-4 mr-2" />
                {loading ? "Publishing..." : "Publish Note"}
              </Button>
            </div>
          </form>
        </CardContent>
      </Card>
    </div>
  );
}

import Link from "next/link";
import { prisma } from "@/lib/prisma";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Search, PenSquare, Clock, Eye, ThumbsUp, FileText } from "lucide-react";

export const dynamic = "force-dynamic";

export default async function NotesPage({
  searchParams,
}: {
  searchParams: { tag?: string; sort?: string; q?: string };
}) {
  const { tag, sort = "latest", q = "" } = searchParams;

  const orderBy: any = {};
  if (sort === "most-viewed") {
    orderBy.views = "desc";
  } else if (sort === "most-upvoted") {
    orderBy.upvotes = { _count: "desc" };
  } else {
    orderBy.createdAt = "desc";
  }

  const where: any = {
    status: "PUBLISHED",
  };

  if (tag) {
    where.tags = { contains: tag };
  }
  if (q) {
    where.title = { contains: q };
  }

  const notes = await prisma.note.findMany({
    where,
    orderBy,
    include: {
      author: { select: { fullName: true, id: true } },
      _count: { select: { upvotes: true } }
    }
  });

  // Calculate unique tags for filter
  const allNotes = await prisma.note.findMany({ where: { status: "PUBLISHED" }, select: { tags: true } });
  const uniqueTags = Array.from(new Set(allNotes.flatMap(n => n.tags.split(',').map(t => t.trim().toLowerCase())).filter(Boolean)));

  return (
    <div className="container mx-auto px-4 py-8 max-w-6xl">
      <div className="flex flex-col md:flex-row md:items-center justify-between mb-8 gap-4">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Community Notes</h1>
          <p className="text-muted-foreground mt-1 text-lg">In-depth guides and architecture breakdowns.</p>
        </div>
        <Link href="/notes/new">
          <Button size="lg" className="h-11 px-8">
            <PenSquare className="mr-2 h-4 w-4" />
            Write a Note
          </Button>
        </Link>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-4 gap-8">
        {/* Sidebar Filters */}
        <div className="space-y-6">
          <Card>
            <CardHeader className="pb-3">
              <CardTitle className="text-base font-semibold">Search Notes</CardTitle>
            </CardHeader>
            <CardContent>
              <form className="relative">
                <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-muted-foreground" />
                <Input name="q" placeholder="Search titles..." defaultValue={q} className="pl-9" />
                {tag && <input type="hidden" name="tag" value={tag} />}
                {sort && <input type="hidden" name="sort" value={sort} />}
              </form>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="pb-3">
              <CardTitle className="text-base font-semibold">Sort By</CardTitle>
            </CardHeader>
            <CardContent className="flex flex-col gap-2">
              <Link href={`/notes?sort=latest${tag ? `&tag=${tag}` : ''}${q ? `&q=${q}` : ''}`}>
                <Button variant={sort === "latest" ? "secondary" : "ghost"} className="w-full justify-start h-9">Latest</Button>
              </Link>
              <Link href={`/notes?sort=most-viewed${tag ? `&tag=${tag}` : ''}${q ? `&q=${q}` : ''}`}>
                <Button variant={sort === "most-viewed" ? "secondary" : "ghost"} className="w-full justify-start h-9">Most Viewed</Button>
              </Link>
              <Link href={`/notes?sort=most-upvoted${tag ? `&tag=${tag}` : ''}${q ? `&q=${q}` : ''}`}>
                <Button variant={sort === "most-upvoted" ? "secondary" : "ghost"} className="w-full justify-start h-9">Most Upvoted</Button>
              </Link>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="pb-3 flex flex-row items-center justify-between space-y-0">
              <CardTitle className="text-base font-semibold">Tags</CardTitle>
              {tag && <Link href={`/notes?sort=${sort}${q ? `&q=${q}` : ''}`} className="text-xs text-primary hover:underline">Clear</Link>}
            </CardHeader>
            <CardContent>
              <div className="flex flex-wrap gap-2">
                {uniqueTags.slice(0, 15).map(t => (
                  <Link key={t} href={`/notes?tag=${t}&sort=${sort}${q ? `&q=${q}` : ''}`}>
                    <span className={`inline-block px-2.5 py-1 text-xs rounded border transition-colors cursor-pointer ${tag === t ? 'bg-primary text-primary-foreground border-primary' : 'bg-muted/50 hover:bg-muted border-border'}`}>
                      {t}
                    </span>
                  </Link>
                ))}
              </div>
            </CardContent>
          </Card>
        </div>

        {/* Notes Grid */}
        <div className="md:col-span-3">
          {notes.length > 0 ? (
            <div className="grid sm:grid-cols-2 gap-4">
              {notes.map((note) => (
                <Link key={note.id} href={`/notes/${note.id}`} className="group h-full">
                  <Card className="h-full hover:border-primary/50 transition-all hover:shadow-md flex flex-col">
                    {note.coverImage && (
                      <div className="h-32 w-full bg-muted overflow-hidden rounded-t-lg">
                        <img src={note.coverImage} alt={note.title} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300" />
                      </div>
                    )}
                    <CardHeader className="p-5 pb-3 grow">
                      <div className="flex flex-wrap gap-2 mb-3">
                        {note.tags.split(',').slice(0, 2).map(t => (
                          <span key={t} className="text-[10px] uppercase tracking-wider bg-secondary text-secondary-foreground font-semibold px-2 py-0.5 rounded">
                            {t.trim()}
                          </span>
                        ))}
                      </div>
                      <CardTitle className="text-xl leading-tight line-clamp-2">{note.title}</CardTitle>
                    </CardHeader>
                    <CardContent className="p-5 pt-0 mt-auto">
                      <p className="text-sm text-muted-foreground mb-4">By {note.author.fullName || "Member"}</p>

                      <div className="flex items-center justify-between text-xs text-muted-foreground pt-4 border-t">
                        <div className="flex items-center gap-1">
                          <Clock className="h-3 w-3" />
                          {note.readTime} min
                        </div>
                        <div className="flex items-center gap-3">
                          <span className="flex items-center gap-1"><Eye className="h-3 w-3" /> {note.views}</span>
                          <span className="flex items-center gap-1"><ThumbsUp className="h-3 w-3" /> {note._count.upvotes}</span>
                        </div>
                      </div>
                    </CardContent>
                  </Card>
                </Link>
              ))}
            </div>
          ) : (
            <div className="flex flex-col items-center justify-center p-12 text-center border rounded-xl border-dashed bg-muted/10">
              <FileText className="h-10 w-10 text-muted-foreground mb-4 opacity-50" />
              <h3 className="text-lg font-medium mb-2">No notes found</h3>
              <p className="text-muted-foreground max-w-sm mx-auto mb-6">
                Try adjusting your search or filters, or be the first to write a note on this topic.
              </p>
              <Link href="/notes/new">
                <Button>Write a Note</Button>
              </Link>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

"use client";

import { useState } from "react";
import { useSession } from "next-auth/react";
