import { User as UserIcon, Save } from "lucide-react";

export default function ProfilePage() {
  const { data: session, update } = useSession();
  const router = useRouter();

  const [fullName, setFullName] = useState(session?.user?.name || "");
  const [bio, setBio] = useState(""); // Simplified, normally fetch detailed user
  const [avatarUrl, setAvatarUrl] = useState(session?.user?.image || "");
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);

  // Note: For a robust app we'd fetch the user's current extended info on load, but we'll stick to a simple controlled form

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setSuccess(false);

    try {
      const res = await fetch("/api/profile", {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ fullName, bio, avatarUrl })
      });

      if (res.ok) {
        setSuccess(true);
        // Force session update
        await update({ name: fullName, image: avatarUrl });
        router.refresh();
      }
    } catch(err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  if (!session) return null;

  return (
    <div className="container mx-auto px-4 py-8 max-w-2xl space-y-8">
      <div>
        <h1 className="text-3xl font-bold tracking-tight">Your Profile</h1>
        <p className="text-muted-foreground mt-1 text-lg">Manage your public presence.</p>
      </div>

      <Card>
        <CardHeader>
          <CardTitle className="text-xl">Profile Information</CardTitle>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleSubmit} className="space-y-6">
            {success && (
              <div className="p-3 bg-green-500/15 text-green-600 border border-green-500/20 rounded-md text-sm">
                Profile updated successfully.
              </div>
            )}

            <div className="flex items-center gap-6">
              <div className="h-24 w-24 rounded-full bg-muted flex items-center justify-center overflow-hidden border-4 border-background shadow-sm">
                {avatarUrl ? (
                  <img src={avatarUrl} alt="Avatar" className="h-full w-full object-cover" />
                ) : (
                  <UserIcon className="h-10 w-10 text-muted-foreground" />
                )}
              </div>
              <div className="flex-1 space-y-2">
                <label className="text-sm font-medium leading-none">Avatar URL</label>
                <Input 
                  value={avatarUrl} 
                  onChange={e => setAvatarUrl(e.target.value)} 
                  placeholder="https://example.com/me.jpg" 
                />
              </div>
            </div>

            <div className="space-y-2">
              <label className="text-sm font-medium leading-none">Full Name</label>
              <Input 
                value={fullName} 
                onChange={e => setFullName(e.target.value)} 
                required 
              />
            </div>

            <div className="space-y-2">
              <label className="text-sm font-medium leading-none">Bio</label>
              <textarea 
                value={bio}
                onChange={e => setBio(e.target.value)}
                className="flex w-full rounded-md border border-input bg-background/50 px-3 py-2 text-sm ring-offset-background placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring min-h-[100px]"
                placeholder="Tell the community about yourself..."
              />
            </div>

            <div className="pt-4 border-t">
              <Button type="submit" disabled={loading}>
                <Save className="h-4 w-4 mr-2" />
                {loading ? "Saving..." : "Save Changes"}
              </Button>
            </div>
          </form>
        </CardContent>
      </Card>
    </div>
  );
}

